import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.DpI_zlPE.js";var i=JSON.parse(`{"title":"家电","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/生活/家电.md","filePath":"ccc/生活/家电.md"}`),a={name:`ccc/生活/家电.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="家电" tabindex="-1">家电 <a class="header-anchor" href="#家电" aria-label="Permalink to “家电”">​</a></h1><h2 id="空调" tabindex="-1">空调 <a class="header-anchor" href="#空调" aria-label="Permalink to “空调”">​</a></h2><p>华凌N8HE1，神机神机神机。</p><p>N8HA1相对HE1有一些细节阉割，以前便宜六百多，现在便宜两三百，不如买HE1。 HA1基本1.6排，HE1基本双排。看看网上最新的拆机，如果HE1阉割1.6排，那HA1便宜两三百也可以考虑。</p><ul><li>格力加钱，焊接做工比美的华凌好点，我觉得不值溢价。</li></ul><p><code>做工差的影响是漏气概率在统计学意义上更大。</code></p><ul><li>海尔中庸。做工介于美的格力之间，价格介于美的格力之间，性价比相对较低。</li></ul><p>空调技术成熟，上世纪50年代就在北美普及，只看谁愿意少赚点。市场老二华凌现在愿意少赚点。个别品牌像奥克斯，为了打价格战，缩水严重。</p><h2 id="电视" tabindex="-1">电视 <a class="header-anchor" href="#电视" aria-label="Permalink to “电视”">​</a></h2><p>1000出头的55寸，可以考虑华为。华为刚出的时候同价位呈现出碾压之势。不过红米和oppo也在跟进。</p><p>TCL雷鸟，同档次面板一般价格较实惠，但机身自带系统较为一般。</p><p>再高价位，推荐直接上OLED，请参考rtings的评测，不要看总分，看需求项目的文字总结，比如xx型号的游戏性能的文字总结。</p><h3 id="肃清索尼流毒" tabindex="-1">肃清索尼流毒 <a class="header-anchor" href="#肃清索尼流毒" aria-label="Permalink to “肃清索尼流毒”">​</a></h3><p>索尼线下利润率奇高，线上返利也是吃饱饱。</p><p>联发科主板，采购面板，价格可以买友商两台一样的硬件！LCD机型上所谓的索尼优化，就是把gamma曲线的红绿拔高，弄得很鲜艳，色准一塌糊涂。根本不能忠实的反映导演的意图！友商遵循IEEE规范，反倒变成色彩不如索尼了。美其名曰，索尼调教！</p><p>索尼的OLED还不错，LG的交钥匙方案，LG调好色了。由于利润空间大，线下砍价空间相对较大。</p>`,16)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};